import React, { useEffect, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import { Jovem } from '../types';

const DashboardInstituicaoEnsino: React.FC = () => {
  const { user } = useAuth();
  const [jovens, setJovens] = useState<Jovem[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const navigate = useNavigate();

  useEffect(() => {
    const fetchJovens = async () => {
      try {
        setLoading(true);
        const response = await fetch('/api/jovens', {
          headers: {
            'Authorization': `Bearer ${localStorage.getItem('token')}`
          }
        });

        if (!response.ok) {
          throw new Error('Erro ao carregar jovens');
        }

        const data = await response.json();
        setJovens(data);
        setLoading(false);
      } catch (error) {
        console.error('Erro:', error);
        setError('Erro ao carregar dados. Por favor, tente novamente.');
        setLoading(false);
      }
    };

    fetchJovens();
  }, []);

  const handleNovoJovem = () => {
    navigate('/instituicao-ensino/jovens/novo');
  };

  return (
    <div className="container mx-auto px-4 py-8">
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-2xl font-bold text-cursor-text-primary">Dashboard da Instituição de Ensino</h1>
        <div className="text-sm text-cursor-text-secondary">
          Bem-vindo(a), <span className="font-medium">{user?.nome}</span>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
        <div className="bg-white rounded-lg shadow p-6">
          <h2 className="text-lg font-semibold mb-2">Jovens Cadastrados</h2>
          <p className="text-3xl font-bold text-cursor-primary">{jovens.length}</p>
          <Link to="/instituicao-ensino/jovens" className="text-cursor-primary text-sm mt-2 inline-block hover:underline">
            Ver todos
          </Link>
        </div>

        <div className="bg-white rounded-lg shadow p-6">
          <h2 className="text-lg font-semibold mb-2">Oportunidades Disponíveis</h2>
          <p className="text-3xl font-bold text-cursor-primary">-</p>
          <Link to="/instituicao-ensino/oportunidades" className="text-cursor-primary text-sm mt-2 inline-block hover:underline">
            Ver todas
          </Link>
        </div>

        <div className="bg-white rounded-lg shadow p-6">
          <h2 className="text-lg font-semibold mb-2">Recomendações Realizadas</h2>
          <p className="text-3xl font-bold text-cursor-primary">-</p>
        </div>
      </div>

      <div className="bg-white rounded-lg shadow mb-8">
        <div className="p-4 border-b border-gray-200 flex justify-between items-center">
          <h2 className="text-lg font-semibold">Jovens Recentes</h2>
          <button 
            onClick={handleNovoJovem}
            className="text-sm text-cursor-primary hover:underline flex items-center"
          >
            <svg className="w-4 h-4 mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
            </svg>
            Adicionar Jovem
          </button>
        </div>
        <div className="p-4">
          {loading ? (
            <div className="text-center py-4">Carregando...</div>
          ) : error ? (
            <div className="text-center py-4 text-red-500">{error}</div>
          ) : jovens.length === 0 ? (
            <div className="text-center py-4 text-cursor-text-secondary">
              Nenhum jovem cadastrado. 
              <button 
                onClick={handleNovoJovem}
                className="text-cursor-primary ml-2 hover:underline"
              >
                Adicionar jovem
              </button>
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="min-w-full divide-y divide-gray-200">
                <thead className="bg-gray-50">
                  <tr>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Nome</th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Email</th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Idade</th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Formação</th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Ações</th>
                  </tr>
                </thead>
                <tbody className="bg-white divide-y divide-gray-200">
                  {jovens.slice(0, 5).map(jovem => (
                    <tr key={jovem.id}>
                      <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-cursor-text-primary">{jovem.nome}</td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-cursor-text-secondary">{jovem.email}</td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-cursor-text-secondary">{jovem.idade}</td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-cursor-text-secondary">{jovem.formacao || '-'}</td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm">
                        <Link to={`/instituicao-ensino/jovens/${jovem.id}`} className="text-cursor-primary hover:underline">
                          Detalhes
                        </Link>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
              {jovens.length > 5 && (
                <div className="p-4 text-right">
                  <Link to="/instituicao-ensino/jovens" className="text-cursor-primary text-sm hover:underline">
                    Ver todos ({jovens.length})
                  </Link>
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default DashboardInstituicaoEnsino;
